script:
frappe.ui.form.on('Sales Invoice', {
    refresh: function(frm) {
        if (frm.doc.docstatus == 0) {
            frm.add_custom_button(__('Preview Print'), function() {
                frappe.set_route('print', frm.doc.doctype, frm.doc.name);
            });
        }
        if (frm.doc.docstatus == 1 && frm.doc.status != 'Paid') {
            frm.add_custom_button(__('Record Payment'), function() {
                frappe.new_doc('Invoice Payment', {
                    sales_invoice: frm.doc.name,
                    amount: frm.doc.balance || frm.doc.total
                });
            });
        }
        // Summary
        var total_qty = 0, total_vat = 0;
        if (frm.doc.items) {
            frm.doc.items.forEach(function(item) {
                total_qty += item.qty || 0;
                total_vat += item.vat_amount || 0;
            });
        }
        frm.set_value('total_qty', total_qty);
        frm.set_value('tax_amount', total_vat);
        if (frm.doc.paid_amount) {
            frm.set_value('balance', frm.doc.total - frm.doc.paid_amount);
        }
    },

    validate: function(frm) {
        // Auto-calculate item amounts
        if (frm.doc.items) {
            frm.doc.items.forEach(function(item) {
                item.amount = (item.qty || 0) * (item.rate || 0);
                if (item.vat_rate) {
                    item.vat_amount = item.amount * item.vat_rate / 100;
                }
            });
        }
    }
});
